"""
Step ID: step01
Step Name: Extract Domain Theta Scores
RQ: results/ch7/7.8.1
Generated: 2026-01-09

PURPOSE:
Extract What and Where domain theta scores from Ch5 5.2.1 (EXCLUDE When due to
77% floor effect), compute participant-level means across 4 tests, and apply
z-score standardization for LPA input.

CRITICAL DECISIONS:
- Use ONLY What and Where domains (exclude When - 77% floor effect per Ch5)
- Aggregate across 4 tests per participant (mean theta per domain)
- Z-score standardization: (X - mean(X)) / sd(X)
- Source: Ch5 5.2.1 ONLY (all domains in one file)

EXPECTED INPUTS:
  - results/ch5/5.2.1/data/step03_theta_scores.csv
    Columns: ['composite_ID', 'theta_what', 'theta_where', 'theta_when']
    Format: CSV with 400 rows (100 UIDs × 4 tests)
    Expected rows: 400

EXPECTED OUTPUTS:
  - data/step01_domain_theta_scores.csv
    Columns: ['UID', 'theta_What', 'theta_Where']
    Format: CSV with participant-level z-scored means
    Expected rows: 100 (one per participant)

VALIDATION CRITERIA:
  - Output has exactly 100 rows (all participants)
  - Z-scored values have mean~0, SD~1 for each domain
  - No missing values (all participants have complete data)

g_code REASONING:
- Approach: Load 5.2.1 theta → Parse composite_ID → Aggregate by UID → Standardize
- Why this approach: Reduces 400 test-level observations to 100 participant-level profiles
- Data flow: 400 rows (test-level) → Group by UID → Mean → Standardize → 100 rows
- Expected performance: ~1 second (simple aggregation)

IMPLEMENTATION NOTES:
- Analysis tool: Custom aggregation (pandas groupby)
- Validation tool: Check z-score properties (mean~0, SD~1)
- Parameters: Exclude When domain, z-score standardization method
- composite_ID format: "A010_1" → UID="A010", test=1
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
import traceback

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch7/7.8.1
LOG_FILE = RQ_DIR / "logs" / "step01_extract_domain_theta_scores.log"
OUTPUT_DIR = RQ_DIR / "data"

# Input from Ch5 5.2.1
INPUT_FILE = PROJECT_ROOT / 'results' / 'ch5' / '5.2.1' / 'data' / 'step03_theta_scores.csv'

# Output
OUTPUT_FILE = OUTPUT_DIR / 'step01_domain_theta_scores.csv'

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 01: Extract Domain Theta Scores")

        # =========================================================================
        # STEP 1: Load Ch5 5.2.1 Theta Scores
        # =========================================================================
        # Expected: 400 rows (100 UIDs × 4 tests), 4 columns
        # Purpose: Source data for LPA (What/Where/When domains)

        log("\n[LOAD] Loading Ch5 5.2.1 theta scores...")
        log(f"[PATH] {INPUT_FILE}")

        df_theta = pd.read_csv(INPUT_FILE)
        log(f"[LOADED] {len(df_theta)} rows, {len(df_theta.columns)} columns")
        log(f"[COLUMNS] {df_theta.columns.tolist()}")

        # Scientific Mantra Checkpoint
        log("\n[VERIFY] Data structure validation")
        expected_cols = ['composite_ID', 'theta_what', 'theta_where', 'theta_when']
        actual_cols = df_theta.columns.tolist()

        if actual_cols != expected_cols:
            raise ValueError(f"Column mismatch. Expected: {expected_cols}, Got: {actual_cols}")

        log(f"[PASS] Columns match expected structure")
        log(f"[INFO] First 5 rows:")
        log(f"{df_theta.head().to_string()}")

        # =========================================================================
        # STEP 2: Parse composite_ID to Extract UID
        # =========================================================================
        # composite_ID format: "A010_1" → UID="A010", test=1
        # Purpose: Enable grouping by participant

        log("\n[PARSE] Extracting UID from composite_ID...")

        df_theta['UID'] = df_theta['composite_ID'].str.split('_').str[0]
        df_theta['test'] = df_theta['composite_ID'].str.split('_').str[1].astype(int)

        log(f"[PARSED] {df_theta['UID'].nunique()} unique participants")
        log(f"[PARSED] {df_theta['test'].nunique()} unique test sessions")
        log(f"[INFO] Test distribution:")
        log(f"{df_theta['test'].value_counts().sort_index().to_string()}")

        # Verify expected structure: 100 UIDs × 4 tests = 400 rows
        n_uids = df_theta['UID'].nunique()
        n_tests = df_theta.groupby('UID')['test'].count()

        if n_uids != 100:
            log(f"[WARNING] Expected 100 UIDs, found {n_uids}")

        incomplete_uids = n_tests[n_tests != 4]
        if len(incomplete_uids) > 0:
            log(f"[WARNING] {len(incomplete_uids)} UIDs with incomplete tests:")
            log(f"{incomplete_uids.to_string()}")

        # Scientific Mantra Checkpoint
        log(f"[VERIFY] Data completeness check")
        log(f"[PASS] UID extraction complete")

        # =========================================================================
        # STEP 3: Aggregate by UID (Mean Theta Across 4 Tests)
        # =========================================================================
        # Purpose: Reduce test-level (400 rows) to participant-level (100 rows)
        # Exclude When domain (77% floor effect documented in Ch5)

        log("\n[AGGREGATE] Computing participant-level mean theta scores...")
        log("[EXCLUDE] When domain (77% floor effect per Ch5 documentation)")

        # Group by UID and compute mean for What and Where domains ONLY
        df_agg = df_theta.groupby('UID').agg({
            'theta_what': 'mean',
            'theta_where': 'mean'
            # EXCLUDE theta_when (floor effect)
        }).reset_index()

        log(f"[AGGREGATED] {len(df_agg)} participants (reduced from {len(df_theta)} test-level rows)")
        log(f"[COLUMNS] {df_agg.columns.tolist()}")
        log(f"[INFO] Descriptive statistics (raw means):")
        log(f"{df_agg[['theta_what', 'theta_where']].describe().to_string()}")

        # Scientific Mantra Checkpoint
        log("\n[VERIFY] Aggregation validation")
        if len(df_agg) != 100:
            log(f"[WARNING] Expected 100 participants, got {len(df_agg)}")
        else:
            log(f"[PASS] Expected participant count (N=100)")

        # =========================================================================
        # STEP 4: Apply Z-Score Standardization
        # =========================================================================
        # Purpose: Standardize domains to mean=0, SD=1 for LPA
        # Formula: z = (X - mean(X)) / sd(X)

        log("\n[STANDARDIZE] Applying z-score standardization...")

        # Rename columns to final format before standardization
        df_agg = df_agg.rename(columns={
            'theta_what': 'theta_What',
            'theta_where': 'theta_Where'
        })

        # Apply z-score transformation
        for domain in ['theta_What', 'theta_Where']:
            mean_val = df_agg[domain].mean()
            sd_val = df_agg[domain].std()

            log(f"[INFO] {domain} - Mean: {mean_val:.4f}, SD: {sd_val:.4f}")

            df_agg[domain] = (df_agg[domain] - mean_val) / sd_val

        log(f"[STANDARDIZED] Z-scored domains")
        log(f"[INFO] Post-standardization statistics:")
        log(f"{df_agg[['theta_What', 'theta_Where']].describe().to_string()}")

        # Scientific Mantra Checkpoint
        log("\n[VERIFY] Standardization validation")
        for domain in ['theta_What', 'theta_Where']:
            z_mean = df_agg[domain].mean()
            z_sd = df_agg[domain].std()

            # Check mean~0, SD~1 (tolerance: 1e-10 for floating point)
            if abs(z_mean) > 1e-10:
                log(f"[WARNING] {domain} z-score mean not ~0: {z_mean}")
            if abs(z_sd - 1.0) > 1e-10:
                log(f"[WARNING] {domain} z-score SD not ~1: {z_sd}")

        log(f"[PASS] Z-score properties validated")

        # =========================================================================
        # STEP 5: Save Output
        # =========================================================================
        # Purpose: LPA input data (participant-level, standardized)

        log(f"\n[SAVE] Writing output to {OUTPUT_FILE}")

        df_agg.to_csv(OUTPUT_FILE, index=False, encoding='utf-8')

        log(f"[SAVED] {len(df_agg)} rows, {len(df_agg.columns)} columns")
        log(f"[COLUMNS] {df_agg.columns.tolist()}")

        # =========================================================================
        # VALIDATION: Check Output Properties
        # =========================================================================

        log("\n[VALIDATION] Final output validation...")

        # Check 1: Row count
        if len(df_agg) != 100:
            raise ValueError(f"Expected 100 rows, got {len(df_agg)}")
        log(f"[PASS] Row count = 100")

        # Check 2: No missing values
        missing_count = df_agg.isnull().sum().sum()
        if missing_count > 0:
            raise ValueError(f"Found {missing_count} missing values")
        log(f"[PASS] No missing values")

        # Check 3: Z-score properties
        for domain in ['theta_What', 'theta_Where']:
            z_mean = abs(df_agg[domain].mean())
            z_sd = abs(df_agg[domain].std() - 1.0)

            if z_mean > 1e-10 or z_sd > 1e-10:
                log(f"[WARNING] {domain} standardization slightly off (mean={z_mean:.2e}, SD_diff={z_sd:.2e})")

        log(f"[PASS] Z-score properties validated")

        log("\n[SUCCESS] Step 01 complete")
        sys.exit(0)

    except Exception as e:
        log(f"\n[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
